import java.util.ArrayList;
import java.util.HashMap;

public class Store {
    public static void main(String[] args) {
        // ArrayList that grows as items are added
        ArrayList<String> cart = new ArrayList<>();
        cart.add("Milk");
        cart.add("Bread");
        cart.add("Eggs");

        // HashMap maps product names to prices
        HashMap<String, Double> prices = new HashMap<>();
        prices.put("Milk", 3.99);
        prices.put("Bread", 2.49);
        prices.put("Eggs", 4.99);

        // Loop through cart and print each item's price
        for (String item : cart) {
            System.out.println(item + ": $" + prices.get(item));
        }

        System.out.println("Total items: " + cart.size());
    }
}
// Expected output:
// Milk: $3.99
// Bread: $2.49
// Eggs: $4.99
// Total items: 3
